// src/components/QuizCustomerList.js
import React, { useEffect, useState } from 'react';
import { fetchQuizCustomers } from '../../services/quizCustomerServices';
import "./services.css"


const Services = () => {
  const [quizCustomers, setQuizCustomers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadQuizCustomers = async () => {
      try {
        const data = await fetchQuizCustomers();
        setQuizCustomers(data);
      } catch (err) {
        setError(err);
      } finally {
        setLoading(false);
      }
    };

    loadQuizCustomers();
  }, []);

  if (loading) return <div>Loading...</div>;
  if (error) return <div>Error: {error.message}</div>;

  return (
    <div className='services'>
      <h1>Quiz Customers</h1>
      <ul>
        {quizCustomers.map(customer => (
          <li key={customer.id}>
            {customer.id}  ||
            {customer.name}
            {customer.email}  ||
            {customer.phoneNumber}  ||
            {customer.gender}  ||
            {customer.id}  ||
            {customer.id}  ||
          </li>
        ))}
      </ul>
    </div>
  );
};

export default Services;
